const syncRunId = `SYNC_${Date.now()}`;
const syncTime = new Date().toISOString();

const transformedProducts = [];
const failedProducts = [];

for (const item of items) {

  const p = item.json;

  try {

    if (!p.id) {
      throw new Error("Missing product id");
    }

    const stock1 = parseFloat(p.stock1 || 0);
    const stock2 = parseFloat(p.stock2 || 0);
    const stock3 = parseFloat(p.stock3 || 0);
    const stock4 = parseFloat(p.stock4 || 0);

    const transformed = {

      sr_product_id: String(p.id || ""),

      inner_id: String(p.innerId || ""),

      product_name_hu: String(
        p.name || ""
      ),

      short_description_hu: String(
        p.short_description || ""
      ),

      long_description_hu: String(
        p.long_description || ""
      ),

      net_price: parseFloat(
        p.price || 0
      ),

      currency_code: "HUF",

      stock_1: stock1,

      stock_2: stock2,

      stock_3: stock3,

      stock_4: stock4,

      total_stock:
        stock1 +
        stock2 +
        stock3 +
        stock4,

      manufacturer: String(
        p.manufacturer || ""
      ),

      primary_product_image: String(
        p.allImages?.mainImage || ""
      ),

      weight: parseFloat(
        p.weight || 0
      ),

      width: parseFloat(
        p.width || 0
      ),

      height: parseFloat(
        p.height || 0
      ),

      length: parseFloat(
        p.length || 0
      ),

      status: String(
        p.status || ""
      ),

      orderable_product: String(
        p.orderable || ""
      ),

      reduce_stock: String(
        p.subtractStock || ""
      ),

      measurement_unit_hu: String(
        p.measurement_unit_hu || ""
      ),

      date_created:
        p.dateCreated || null,

      date_updated:
        p.dateUpdated || null,

      inserted_at: syncTime,

      last_synced_at: syncTime,

      is_active: true,

      sync_run_id: syncRunId,

      sync_status: "success"
    };

    transformedProducts.push({
      json: transformed
    });

  } catch (error) {

    failedProducts.push({
      json: {

        failed_at: syncTime,

        sync_run_id: syncRunId,

        sr_product_id: String(
          p.id || ""
        ),

        error_message: error.message,

        raw_payload: JSON.stringify(p)
      }
    });

  }
}

return transformedProducts;
